pragma solidity ^0.8.26;

contract TransparentProxy {
    bytes32 private constant IMPLEMENTATION_SLOT = [[SLOT impl_slot_const]];
    bytes32 private constant ADMIN_SLOT = 0xb53127684a568b3173ae13b9f8a6016e243e63b6e8ee1178d6a717850b5d6103;

    event Upgraded(address indexed newImplementation);
    error AdminCallsProhibited();
    error Unauthorized();

    constructor(address logic, address admin) {
        assembly {
            sstore(IMPLEMENTATION_SLOT, logic)
            sstore(ADMIN_SLOT, admin)
        }
    }

    function upgradeTo(address newLogic) external {
        address admin;
        assembly {
            admin := sload(ADMIN_SLOT)
        }
        if (msg.sender != admin) revert Unauthorized();
        assembly {
            sstore(IMPLEMENTATION_SLOT, newLogic)
        }
        emit Upgraded(newLogic);
    }

    fallback() external payable {
        address admin;
        assembly {
            admin := sload(ADMIN_SLOT)
        }
        if ([[SLOT admin_check]]) revert AdminCallsProhibited();

        address impl;
        assembly {
            impl := sload(IMPLEMENTATION_SLOT)
            calldatacopy(0, 0, calldatasize())
            let result := [[SLOT delegate_call]]
            returndatacopy(0, 0, returndatasize())
            switch result
            case 0 { revert(0, returndatasize()) }
            default { return(0, returndatasize()) }
        }
    }

    receive() external payable {}
}

contract SimpleCounter {
    uint256 public count;

    function increment() external {
        count++;
    }

    function getCount() external view returns (uint256) {
        return count;
    }
}
